## Example Secure IAM Policies (JSON)

### 1. Node‑Group IAM Role – Least Privilege  
Only actions required for the node to join the cluster and pull images.

```json
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "EKSWorkerNode",
      "Effect": "Allow",
      "Action": [
        "eks:DescribeCluster",
        "ecr:GetAuthorizationToken",
        "ecr:BatchGetImage",
        "ecr:GetDownloadUrlForLayer",
        "logs:CreateLogStream",
        "logs:PutLogEvents",
        "cloudwatch:PutMetricData"
      ],
      "Resource": "*"
    }
  ]
}
```

*No `*:*` wildcard; scoped to only the actions the node needs.*

### 2. Service‑Account IAM Role for a “payments” microservice  
Allows read/write to a specific DynamoDB table and read‑only access to a secret.

```json
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "DynamoDBPayments",
      "Effect": "Allow",
      "Action": [
        "dynamodb:GetItem",
        "dynamodb:PutItem",
        "dynamodb:UpdateItem",
        "dynamodb:Query"
      ],
      "Resource": "arn:aws:dynamodb:us-east-1:123456789012:table/Payments"
    },
    {
      "Sid": "ReadPaymentSecret",
      "Effect": "Allow",
      "Action": [
        "secretsmanager:GetSecretValue"
      ],
      "Resource": "arn:aws:secretsmanager:us-east-1:123456789012:secret/payments/*"
    }
  ]
}
```

*Attach this role to the Kubernetes ServiceAccount via IRSA (`eks.amazonaws.com/role-arn`).*

### 3. WAF Managed Rule Group (Terraform snippet for reference)

```hcl
resource "aws_wafv2_web_acl" "api_gateway_acl" {
  name        = "multi-region-eks-api-waf"
  scope       = "REGIONAL"
  description = "Protect API Gateway from OWASP Top‑10 attacks"

  default_action {
    allow {}
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "api-waf"
    sampled_requests_enabled   = true
  }

  rule {
    name     = "AWSManagedRulesCommonRuleSet"
    priority = 1

    override_action {
      none {}
    }

    statement {
      managed_rule_group_statement {
        name        = "AWSManagedRulesCommonRuleSet"
        vendor_name = "AWS"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "aws-common-rules"
      sampled_requests_enabled   = true
    }
  }

  # Rate‑based rule to mitigate DoS
  rule {
    name     = "RateLimit"
    priority = 2

    statement {
      rate_based_statement {
        limit              = 2000   # requests per 5‑minute period per IP
        aggregate_key_type = "IP"
      }
    }

    action {
      block {}
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "rate-limit"
      sampled_requests_enabled   = true
    }
  }
}
```

*The same ACL can be associated with the API Gateway via `aws_api_gateway_stage`.*

